from itertools import combinations, permutations


class Solution:
    def maxTaskAssign(self, tasks, workers, pills, strength):
        n, m = len(tasks), len(workers)
        for k in range(min(n, m), 0, -1):
            found = False
            for task_idx in combinations(range(n), k):
                t_sub = [tasks[i] for i in task_idx]
                for work_idx in combinations(range(m), k):
                    w_sub = [workers[i] for i in work_idx]
                    for perm in permutations(range(k)):
                        needed = 0
                        ok = True
                        for i in range(k):
                            w = w_sub[perm[i]]
                            t = t_sub[i]
                            if w >= t:
                                continue
                            elif w + strength >= t:
                                needed += 1
                            else:
                                ok = False
                                break
                        if ok and needed <= pills:
                            found = True
                            break
                    if found:
                        break
                if found:
                    break
            if found:
                return k
        return 0

