from collections import deque


class Solution:
    def maxTaskAssign(self, tasks, workers, pills, strength):
        tasks = sorted(tasks)
        workers = sorted(workers)
        n, m = len(tasks), len(workers)

        def check(k):
            if k == 0:
                return True
            p = pills
            ptr = m - 1
            window = deque()
            for i in range(k - 1, -1, -1):
                while ptr >= m - k and workers[ptr] + strength >= tasks[i]:
                    window.append(workers[ptr])
                    ptr -= 1
                if not window:
                    return False
                if window[0] >= tasks[i]:
                    window.popleft()
                else:
                    if p == 0:
                        return False
                    p -= 1
                    window.pop()
            return True

        lo, hi, ans = 0, min(n, m), 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if check(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

