var maxTaskAssign = function(tasks, workers, pills, strength) {
    tasks = tasks.slice().sort((a, b) => a - b);
    workers = workers.slice().sort((a, b) => a - b);
    const n = tasks.length, m = workers.length;

    function check(k) {
        if (k === 0) return true;
        let p = pills;
        let ptr = m - 1;
        const window = [];
        for (let i = k - 1; i >= 0; i--) {
            while (ptr >= m - k && workers[ptr] + strength >= tasks[i]) {
                window.push(workers[ptr]);
                ptr -= 1;
            }
            if (window.length === 0) return false;
            if (window[0] >= tasks[i]) {
                window.shift();
            } else {
                if (p === 0) return false;
                p -= 1;
                window.pop();
            }
        }
        return true;
    }

    let lo = 0, hi = Math.min(n, m), ans = 0;
    while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (check(mid)) {
            ans = mid;
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return ans;
};
